import axios from "axios";

export const API_BASE = "http://localhost:5050/api";

export const fetchCompanies = async () => {
  const res = await axios.get(`${API_BASE}/companies`);
  console.log("Companies API Response:", res.data);  // 👈 Check karo yaha
  return res.data.data || res.data;  // dono case handle hoga
};

export const fetchStockData = async (companyId) => {
  const res = await axios.get(`${API_BASE}/stocks/${companyId}`);
  console.log("Stock API Response:", res.data);  // 👈 Check karo yaha
  return res.data.data || res.data;  // dono case handle hoga
};
